class FileManager:
    def __init__(self, path, mode='r'):
        self.path = path
        self.mode = mode
        self.file = None
    def __enter__(self):
        self.file = open(self.path, self.mode)
        return self.file
    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.file:
            self.file.close()
        return False
with FileManager('{path}', 'r') as f:
