import socket
import threading
clients = []
def handle_client(client_sock, addr):
    print(f'Client connected: {addr}')
    clients.append(client_sock)
    try:
        while True:
            data = client_sock.recv(1024)
            if not data:
                break
            msg = f'{addr}: {data.decode()}'
            print(msg)
            for c in clients:
                if c != client_sock:
                    try:
                        c.send(msg.encode())
                    except:
                        pass
    except:
        pass
    finally:
        clients.remove(client_sock)
        client_sock.close()
        print(f'Client disconnected: {addr}')
